@app.route('/api/transaction-test', methods=['POST'])
def transaction_test():
    """Test database transactions with rollback"""
    try:
        data = request.get_json()
        
        with capture_span('database.transaction', span_type='db'):
            conn = get_db_connection()
            cursor = conn.cursor()
            
            try:
                # Start transaction
                cursor.execute("BEGIN")
                
                # Multiple operations
                cursor.execute(
                    "INSERT INTO users (username, email) VALUES (%s, %s)",
                    (data.get('username'), data.get('email'))
                )
                
                # Simulate error condition
                if data.get('force_error'):
                    raise ValueError("Forced transaction error")
                
                cursor.execute("COMMIT")
                label(transaction_status='committed')
                
            except Exception as e:
                cursor.execute("ROLLBACK")
                label(transaction_status='rolled_back')
                raise e
            
            finally:
                cursor.close()
                conn.close()
        
        return jsonify({'status': 'success', 'message': 'Transaction completed'})
    
    except Exception as e:
        logger.error(f"Transaction error: {str(e)}")
        apm.capture_exception()
        return jsonify({'error': str(e)}), 500


